INSERT INTO reviews (id, product_id, author_id, rating, body, created_at, updated_at) VALUES
  ('rev-001', 'prod-001', 'user-001', 5, 'Absolutely love this keyboard! The Cherry MX Blues are so satisfying.', '2025-02-01T10:00:00.000Z', '2025-02-01T10:00:00.000Z'),
  ('rev-002', 'prod-001', 'user-002', 4, 'Great keyboard, a bit loud for office use though.', '2025-02-02T11:00:00.000Z', '2025-02-02T11:00:00.000Z'),
  ('rev-003', 'prod-001', 'user-006', 5, 'Best keyboard I have ever used. Build quality is exceptional.', '2025-02-03T12:00:00.000Z', '2025-02-03T12:00:00.000Z'),
  ('rev-004', 'prod-002', 'user-001', 4, 'Comfortable mouse, battery lasts forever.', '2025-02-04T13:00:00.000Z', '2025-02-04T13:00:00.000Z'),
  ('rev-005', 'prod-002', 'user-007', 3, 'Decent mouse but the scroll wheel feels cheap.', '2025-02-05T14:00:00.000Z', '2025-02-05T14:00:00.000Z'),
  ('rev-006', 'prod-003', 'user-002', 5, 'Works perfectly with my MacBook. All ports function as expected.', '2025-02-06T15:00:00.000Z', '2025-02-06T15:00:00.000Z'),
  ('rev-007', 'prod-003', 'user-006', 4, 'Good hub but gets warm under heavy use.', '2025-02-07T16:00:00.000Z', '2025-02-07T16:00:00.000Z'),
  ('rev-008', 'prod-004', 'user-001', 5, 'My feet thank me. Huge difference for standing desk users.', '2025-02-08T09:00:00.000Z', '2025-02-08T09:00:00.000Z'),
  ('rev-009', 'prod-004', 'user-007', 4, 'Good quality mat, wish it was a bit larger.', '2025-02-09T10:00:00.000Z', '2025-02-09T10:00:00.000Z'),
  ('rev-010', 'prod-005', 'user-001', 5, 'The noise cancellation is incredible. Perfect for focus work.', '2025-02-10T11:00:00.000Z', '2025-02-10T11:00:00.000Z'),
  ('rev-011', 'prod-005', 'user-002', 5, 'Premium sound quality. Worth every penny.', '2025-02-11T12:00:00.000Z', '2025-02-11T12:00:00.000Z'),
  ('rev-012', 'prod-005', 'user-006', 4, 'Great headphones but a bit heavy for long sessions.', '2025-02-12T13:00:00.000Z', '2025-02-12T13:00:00.000Z'),
  ('rev-013', 'prod-005', 'user-007', 5, 'These headphones changed my commute. Amazing ANC.', '2025-02-13T14:00:00.000Z', '2025-02-13T14:00:00.000Z'),
  ('rev-014', 'prod-006', 'user-002', 3, 'Image quality is good but autofocus is slow.', '2025-02-14T15:00:00.000Z', '2025-02-14T15:00:00.000Z'),
  ('rev-015', 'prod-006', 'user-006', 4, 'Good webcam for the price. Privacy shutter is a nice touch.', '2025-02-15T16:00:00.000Z', '2025-02-15T16:00:00.000Z'),
  ('rev-016', 'prod-007', 'user-001', 5, 'Reduces eye strain significantly. Love the warm light mode.', '2025-02-16T09:00:00.000Z', '2025-02-16T09:00:00.000Z'),
  ('rev-017', 'prod-007', 'user-007', 4, 'Solid build quality, easy to install.', '2025-02-17T10:00:00.000Z', '2025-02-17T10:00:00.000Z'),
  ('rev-018', 'prod-009', 'user-002', 5, 'Sturdy and adjustable. Improved my posture noticeably.', '2025-02-18T11:00:00.000Z', '2025-02-18T11:00:00.000Z'),
  ('rev-019', 'prod-009', 'user-006', 4, 'Good laptop stand, minimal wobble.', '2025-02-19T12:00:00.000Z', '2025-02-19T12:00:00.000Z'),
  ('rev-020', 'prod-010', 'user-001', 4, 'Nice organizer, keeps my desk tidy.', '2025-02-20T13:00:00.000Z', '2025-02-20T13:00:00.000Z'),
  ('rev-021', 'prod-011', 'user-001', 4, 'Good sound for its size. Waterproof is great for the shower.', '2025-02-21T14:00:00.000Z', '2025-02-21T14:00:00.000Z'),
  ('rev-022', 'prod-011', 'user-002', 3, 'Bass is lacking compared to larger speakers.', '2025-02-22T15:00:00.000Z', '2025-02-22T15:00:00.000Z'),
  ('rev-023', 'prod-011', 'user-007', 5, 'Perfect portable speaker. Took it camping, held up great.', '2025-02-23T16:00:00.000Z', '2025-02-23T16:00:00.000Z'),
  ('rev-024', 'prod-012', 'user-001', 5, 'Best earbuds I have owned. ANC rivals over-ear headphones.', '2025-02-24T09:00:00.000Z', '2025-02-24T09:00:00.000Z'),
  ('rev-025', 'prod-012', 'user-006', 4, 'Great sound, but the case is a fingerprint magnet.', '2025-02-25T10:00:00.000Z', '2025-02-25T10:00:00.000Z'),
  ('rev-026', 'prod-013', 'user-002', 5, 'Super precise. The adjustable weight is a game changer.', '2025-02-26T11:00:00.000Z', '2025-02-26T11:00:00.000Z'),
  ('rev-027', 'prod-013', 'user-007', 4, 'Good gaming mouse, but the software is clunky.', '2025-02-27T12:00:00.000Z', '2025-02-27T12:00:00.000Z'),
  ('rev-028', 'prod-014', 'user-001', 5, 'Per-key RGB is beautiful. Macros work flawlessly.', '2025-02-28T13:00:00.000Z', '2025-02-28T13:00:00.000Z'),
  ('rev-029', 'prod-014', 'user-006', 4, 'Solid gaming keyboard. The wrist rest could be better.', '2025-03-01T14:00:00.000Z', '2025-03-01T14:00:00.000Z'),
  ('rev-030', 'prod-015', 'user-002', 4, 'Large and smooth. Perfect for low DPI gaming.', '2025-03-02T15:00:00.000Z', '2025-03-02T15:00:00.000Z'),
  ('rev-031', 'prod-015', 'user-007', 5, 'Covers my entire desk. Love it.', '2025-03-03T16:00:00.000Z', '2025-03-03T16:00:00.000Z'),
  ('rev-032', 'prod-016', 'user-001', 5, 'Freed up so much desk space. Smooth adjustment.', '2025-03-04T09:00:00.000Z', '2025-03-04T09:00:00.000Z'),
  ('rev-033', 'prod-016', 'user-006', 4, 'Solid arm, holds my 27-inch monitor without sagging.', '2025-03-05T10:00:00.000Z', '2025-03-05T10:00:00.000Z'),
  ('rev-034', 'prod-017', 'user-002', 3, 'Comfortable but started flattening after a month.', '2025-03-06T11:00:00.000Z', '2025-03-06T11:00:00.000Z'),
  ('rev-035', 'prod-017', 'user-007', 4, 'Decent wrist rest for the price.', '2025-03-07T12:00:00.000Z', '2025-03-07T12:00:00.000Z'),
  ('rev-036', 'prod-018', 'user-001', 4, 'Great lighting for video calls. Easy to set up.', '2025-03-08T13:00:00.000Z', '2025-03-08T13:00:00.000Z'),
  ('rev-037', 'prod-019', 'user-002', 5, 'Crystal clear audio. Perfect for podcasting.', '2025-03-09T14:00:00.000Z', '2025-03-09T14:00:00.000Z'),
  ('rev-038', 'prod-019', 'user-001', 4, 'Good mic for the price. Pop filter is a nice bonus.', '2025-03-10T15:00:00.000Z', '2025-03-10T15:00:00.000Z'),
  ('rev-039', 'prod-020', 'user-006', 4, 'Sleek design, holds headphones securely.', '2025-03-11T16:00:00.000Z', '2025-03-11T16:00:00.000Z'),
  ('rev-040', 'prod-021', 'user-007', 5, 'Finally an HDMI cable that supports 4K 120Hz without issues.', '2025-03-12T09:00:00.000Z', '2025-03-12T09:00:00.000Z'),
  ('rev-041', 'prod-022', 'user-001', 4, 'Good cable, braided design feels premium.', '2025-03-13T10:00:00.000Z', '2025-03-13T10:00:00.000Z'),
  ('rev-042', 'prod-023', 'user-002', 5, 'Plenty of outlets and USB ports. Surge protection gives peace of mind.', '2025-03-14T11:00:00.000Z', '2025-03-14T11:00:00.000Z'),
  ('rev-043', 'prod-024', 'user-006', 4, 'Adjustable brightness is great. USB port charges my phone overnight.', '2025-03-15T12:00:00.000Z', '2025-03-15T12:00:00.000Z'),
  ('rev-044', 'prod-024', 'user-001', 5, 'Perfect desk lamp. The warm light mode is easy on the eyes.', '2025-03-16T13:00:00.000Z', '2025-03-16T13:00:00.000Z'),
  ('rev-045', 'prod-025', 'user-007', 4, 'Comfortable cushion. Made long work days bearable.', '2025-03-17T14:00:00.000Z', '2025-03-17T14:00:00.000Z'),
